import { callLlm, sanitizeLlmResponse } from "@ubiquity-os/plugin-sdk";
export class LlmIssueMatcher {
    _context;
    _config;
    constructor(_context, _config) {
        this._context = _context;
        this._config = _config;
    }
    async match(pr, diff, issues) {
        const chunks = this._chunkIssues(issues, this._config.maxIssuesPerLlmCall);
        const results = await Promise.all(chunks.map((chunk) => this._matchChunk(pr, diff, chunk)));
        const byKey = new Map();
        for (const r of results) {
            for (const s of r) {
                const key = `${s.owner}/${s.repo}#${s.number}`;
                const existing = byKey.get(key);
                if (!existing || s.confidence > existing.confidence)
                    byKey.set(key, s);
            }
        }
        return [...byKey.values()].sort((a, b) => b.confidence - a.confidence);
    }
    _chunkIssues(issues, size) {
        if (issues.length <= size)
            return [issues];
        const chunks = [];
        for (let i = 0; i < issues.length; i += size) {
            chunks.push(issues.slice(i, i + size));
        }
        return chunks;
    }
    async _matchChunk(pr, diff, issues) {
        const payload = {
            pullRequest: {
                owner: pr.owner,
                repo: pr.repo,
                number: pr.number,
                title: pr.title,
                body: pr.body,
            },
            diff: this._truncate(diff.text, 24000),
            issues: issues.map((i) => ({
                owner: i.owner,
                repo: i.repo,
                number: i.number,
                title: i.title,
                body: this._truncate(i.body, 2000),
                labels: i.labels,
                url: i.url,
            })),
        };
        const system = "You match GitHub pull requests to the most likely existing open issues. " + "Return only valid JSON. Confidence must be between 0 and 1.";
        const user = "Given the pull request and its diff plus candidate issues, return the best matching issues. " +
            "Prefer issues whose title/body aligns with code changes and file paths. " +
            "Output format: { suggestions: [{ owner, repo, number, confidence, reason }] }.";
        const completion = await callLlm({
            response_format: { type: "json_object" },
            messages: [
                { role: "system", content: system },
                { role: "user", content: `${user}\n\n${JSON.stringify(payload)}` },
            ],
        }, this._context);
        const text = completion?.choices?.[0]?.message?.content;
        if (!text)
            return [];
        const parsed = JSON.parse(sanitizeLlmResponse(text));
        if (!parsed?.suggestions?.length)
            return [];
        return parsed.suggestions
            .map((s) => ({
            owner: s.owner,
            repo: s.repo,
            number: s.number,
            confidence: this._clamp01(s.confidence),
            reason: s.reason,
        }))
            .filter((s) => Number.isFinite(s.confidence) && s.owner && s.repo && Number.isFinite(s.number));
    }
    _truncate(input, maxLen) {
        if (input.length <= maxLen)
            return input;
        return input.slice(0, maxLen);
    }
    _clamp01(value) {
        if (value < 0)
            return 0;
        if (value > 1)
            return 1;
        return value;
    }
}
