const SUGGESTION_MARKER = "<!-- daemon-task-matcher:suggestions -->";
export class MatcherCommentParser {
    parseCheckedIssues(body) {
        const hasMarker = body.includes(SUGGESTION_MARKER);
        if (!hasMarker)
            return { checked: [], markerFound: hasMarker };
        const checked = [];
        const lines = body.split(/\r?\n/);
        for (const line of lines) {
            const trimmed = line.trim();
            if (!trimmed.startsWith("- [x] ") && !trimmed.startsWith("- [X] "))
                continue;
            const match = /- \[[xX]\]\s+([^\s#/]+)\/([^\s#]+)#(\d+)/.exec(trimmed);
            if (!match)
                continue;
            const owner = match[1];
            const repo = match[2];
            const number = Number(match[3]);
            if (!owner || !repo || !Number.isFinite(number))
                continue;
            checked.push({ owner, repo, number });
        }
        const uniq = new Map();
        for (const c of checked) {
            uniq.set(`${c.owner}/${c.repo}#${c.number}`, c);
        }
        return { checked: [...uniq.values()], markerFound: hasMarker };
    }
    extractSuggestions(body) {
        const hasMarker = body.includes(SUGGESTION_MARKER);
        if (!hasMarker)
            return [];
        const suggestions = [];
        const lines = body.split(/\r?\n/);
        for (const line of lines) {
            const trimmed = line.trim();
            if (!trimmed.startsWith("- ["))
                continue;
            const match = /- \[[ xX]\]\s+([^\s#/]+)\/([^\s#]+)#(\d+)\s+\((\d+(?:\.\d+)?)\)/.exec(trimmed);
            if (!match)
                continue;
            const owner = match[1];
            const repo = match[2];
            const number = Number(match[3]);
            const confidence = Number(match[4]);
            if (!owner || !repo || !Number.isFinite(number) || !Number.isFinite(confidence))
                continue;
            suggestions.push({ owner, repo, number, confidence });
        }
        return suggestions;
    }
}
