export class UnassignedPricedIssueFinder {
    _context;
    _config;
    constructor(_context, _config) {
        this._context = _context;
        this._config = _config;
    }
    async listOpenUnassignedIssues(repos) {
        const allIssues = [];
        for (const repo of repos) {
            const issues = await this._context.octokit.paginate(this._context.octokit.rest.issues.listForRepo, {
                owner: repo.owner,
                repo: repo.repo,
                state: "open",
                per_page: 100,
                assignee: "none",
            });
            for (const issue of issues) {
                const issueSummary = this._toCandidateIssue(repo.owner, repo.repo, issue);
                if (!issueSummary)
                    continue;
                allIssues.push(issueSummary);
            }
        }
        return allIssues;
    }
    _toCandidateIssue(owner, repo, issue) {
        const i = issue;
        if (i.pull_request)
            return null;
        const labels = (i.labels ?? []).map((l) => (typeof l === "string" ? l : (l?.name ?? ""))).filter((v) => v.length > 0);
        if (this._config.requirePriceLabel) {
            const rx = new RegExp(this._config.priceLabelRegex);
            if (!labels.some((l) => rx.test(l)))
                return null;
        }
        const assignees = i.assignees ?? [];
        if (assignees.length > 0)
            return null;
        return {
            owner,
            repo,
            number: i.number,
            title: i.title ?? "",
            body: i.body ?? "",
            url: i.html_url ?? "",
            labels,
        };
    }
}
